const body = $input.first().json.body || $input.first().json;

// Meta sends: {object:'instagram', entry:[{id, messaging:[{sender:{id}, recipient:{id}, timestamp, message:{mid,text}}]}]}
const entry = body?.entry?.[0];
const messaging = entry?.messaging?.[0];

if (!messaging || messaging.read || messaging.delivery) return []; // ignore read receipts

const senderId = messaging.sender?.id;
const recipientId = messaging.recipient?.id;
const messageText = messaging.message?.text || '[non-text message]';
const messageId = messaging.message?.mid;
const timestamp = messaging.timestamp;

if (!senderId || !messageText) return [];

return [{ json: { senderId, recipientId, messageText, messageId, timestamp, igPageId: recipientId } }];

const profile = $input.first().json;
const msgData = $('Extract IG Message Data').first().json;
return [{ json: {
  ...msgData,
  contactName: profile.name || profile.username || 'Instagram User',
  igUsername: profile.username || null
} }];

const now = new Date();
const hkOffset = 8 * 60;
const utcMinutes = now.getUTCHours() * 60 + now.getUTCMinutes();
const hkMinutes = (utcMinutes + hkOffset) % (24 * 60);
const hkDay = new Date(now.getTime() + hkOffset * 60000).getUTCDay();

const isWeekday = hkDay >= 1 && hkDay <= 6;
const isOpenHours = hkMinutes >= 540 && hkMinutes < 1140;
const isBusinessHours = isWeekday && isOpenHours;

return [{ json: { ...$input.first().json, isBusinessHours } }];

const contactData = $input.first().json;
const contacts = contactData.contacts || [];
const existingContact = contacts[0] || null;

let conversationHistory = [];
if (existingContact) {
  const historyField = existingContact.customFields?.find(f => f.key === 'scalar_ig_history');
  if (historyField?.value) {
    try { conversationHistory = JSON.parse(historyField.value).slice(-12); } catch(e) {}
  }
}

const msgData = $('Merge Profile + Message').first().json;

return [{ json: {
  ...msgData,
  existingContact,
  ghlContactId: existingContact?.id || null,
  conversationHistory,
  resolvedName: existingContact?.firstName || msgData.contactName
} }];

const aiRaw = $input.first().json.choices[0].message.content;

let bookingData = null;
const bookingMatch = aiRaw.match(/\[BOOKING_INTENT\]([\s\S]*?)\[\/BOOKING_INTENT\]/);
if (bookingMatch) {
  try { bookingData = JSON.parse(bookingMatch[1]); } catch(e) {}
}

const cleanResponse = aiRaw.replace(/\[BOOKING_INTENT\][\s\S]*?\[\/BOOKING_INTENT\]/g, '').trim();

const prevHistory = $('Build IG Conversation Context').first().json.conversationHistory || [];
const updatedHistory = [
  ...prevHistory,
  { role: 'user', content: $('Build IG Conversation Context').first().json.messageText },
  { role: 'assistant', content: cleanResponse }
].slice(-20);

const ctx = $('Build IG Conversation Context').first().json;

return [{ json: {
  ...ctx,
  aiResponse: cleanResponse,
  bookingData,
  hasBookingIntent: !!bookingData,
  updatedHistoryJson: JSON.stringify(updatedHistory)
} }];
